myEmitter.on('event', (data) => {
  console.log('An event occurred:', data);
});

myEmitter.emit('event', { id: 1, message: 'Hello world' });

const user = {
  name: "Alice",
  age: 30
};

const userProxy = new Proxy(user, {
  get(target, prop) {
    if (prop in target) {
      return target[prop];
    } else {
      throw new ReferenceError(`Property \"${prop}\" does not exist.`);
    }
  }
});

console.log(userProxy.name); // Alice
console.log(userProxy.age);  // 30
// console.log(userProxy.email); // Throws ReferenceError

const userWithValidation = new Proxy(user, {
  get(target, prop) {
    if (prop in target) {
      return target[prop];
    } else {
      throw new ReferenceError(`Property \"${prop}\" does not exist.`);
    }
  },
  set(target, prop, value) {
    if (prop === 'age' && typeof value !== 'number') {
      throw new TypeError('Age must be a number.');
    }
    target[prop] = value;
    return true;
  }
});

userWithValidation.age = 35;  // Works
// userWithValidation.age = 'thirty'; // Throws TypeError
userWithValidation.email = 'alice@example.com'; // Allowed

const protectedUser = new Proxy(user, {
  deleteProperty(target, prop) {
    if (prop === 'name') {
      throw new Error('Cannot delete the name property.');
    }
    delete target[prop];
    console.log(`Deleted property: ${prop}`);
    return true;
  }
});

// delete protectedUser.name; // Throws Error
delete protectedUser.age; // Logs 'Deleted property: age'

import WebSocket, { WebSocketServer } from 'ws';

const wss = new WebSocketServer({ port: 8080 });

wss.on('connection', (ws) => {
  console.log('New client connected');

  ws.on('message', (message) => {
    console.log(`Received: ${message}`);
    // Broadcast the message to all clients
    wss.clients.forEach(client => {
      if (client !== ws && client.readyState === WebSocket.OPEN) {
        client.send(message.toString());
      }
    });
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});

console.log('WebSocket server started on ws://localhost:8080');

const ws = new WebSocket('ws://localhost:8080');

ws.onopen = () => {
  console.log('Connected to the server');
  // Send a greeting message
  ws.send('Hello from client!');
};

ws.onmessage = (event) => {
  console.log(`Received from server: ${event.data}`);
};

ws.onclose = () => {
  console.log('Disconnected from server');
};

// Send a chat message every 5 seconds
setInterval(() => {
  const msg = `Current time: ${new Date().toLocaleTimeString()}`;
  ws.send(msg);
  console.log(`Sent: ${msg}`);
}, 5000);

class ValidationError extends Error {
    constructor(message: string) {
        super(message);
        this.name = "ValidationError";
        Object.setPrototypeOf(this, ValidationError.prototype); // Restore prototype chain
    }
}

function validateAge(age: number) {
    if (age < 0 || age > 150) {
        throw new ValidationError("Age must be between 0 and 150.");
    }
    return true;
}

try {
    validateAge(200);
} catch (error) {
    if (error instanceof ValidationError) {
        console.error("Validation failed:", error.message);
    } else {
        console.error("An unexpected error occurred:", error);
    }
}

class MyMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"Creating class {name}")
        # Add a new attribute to the class
        dct['id'] = 123
        return super().__new__(cls, name, bases, dct)

class InterfaceMeta(type):
    def __init__(cls, name, bases, dct):
        if 'required_method' not in dct:
            raise TypeError(f"Class {name} must implement 'required_method'.")
        super().__init__(name, bases, dct)

class GoodClass(metaclass=InterfaceMeta):
    def required_method(self):
        print("Implemented")

